const make = (tag,className,text) => { const node=document.createElement(tag); if(className) node.className=className; if(text!==undefined) node.textContent=text; return node; };
const title=typeof data.title==='string'&&data.title.trim()?data.title.trim():'Glossary'; const entries=Array.isArray(data.entries)?data.entries:[];
const frame=make('section','frame'); frame.setAttribute('aria-label',title); const heading=make('header','heading'); heading.appendChild(make('div','eyebrow','Glossary')); heading.appendChild(make('h2','',title)); if(data.description) heading.appendChild(make('div','description',String(data.description))); frame.appendChild(heading);
if(!entries.length){ frame.appendChild(make('div','empty','No glossary terms to show yet.')); }
else{
  const groups=new Map(); entries.forEach((item)=>{ const key=item&&typeof item.group==='string'&&item.group.trim()?item.group.trim():'Terms'; if(!groups.has(key)) groups.set(key,[]); groups.get(key).push(item); });
  const content=make('div','content'); const showGroups=groups.size>1||entries.some((item)=>item&&item.group);
  groups.forEach((items,label)=>{
    const section=make('section','group'); if(showGroups) section.appendChild(make('h3','group-title',label)); const list=make('dl');
    items.forEach((item)=>{
      const row=make('div','entry'); const term=make('dt','',item&&item.term!=null?String(item.term):'Untitled term');
      const aliases=Array.isArray(item&&item.aliases)?item.aliases:[]; if(aliases.length){ const wrap=make('div','aliases'); aliases.forEach((alias)=>wrap.appendChild(make('span','alias',String(alias)))); term.appendChild(wrap); } row.appendChild(term);
      const definition=make('dd','',item&&item.definition!=null?String(item.definition):'—'); if(item&&item.example) definition.appendChild(make('div','example','Example · '+String(item.example))); row.appendChild(definition); list.appendChild(row);
    });
    section.appendChild(list); content.appendChild(section);
  });
  frame.appendChild(content);
}
root.appendChild(frame);
parent.appendChild(host);

